/*
 * Symbols that are new to libc with the thread merge.
 *
 * pthread_create and pthread_cancel were historically not exported by
 * libc at all (link time was satisfied by weak abort stubs in the
 * libpthread shim), so they enter the current public version node.
 */
DF606.0 {
    pthread_cancel;
    pthread_create;
};

/*
 * The rest were previously only exported by libthread_xu and are all
 * internal contract symbols (cancellation entry points, debugger
 * hooks, static lock objects), hence the private namespace.
 */
